#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

# Function to extract text from PDF
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $pages = $pdf->pages;

    my @text;
    for (my $page = 1; $page <= $pages; $page++) {
        my $page_obj = $pdf->open_page($page);
        my $text = PDF::Text::Simple->new($page_obj);
        push @text, $text->text;
    }
    return join("\n", @text);
}

# Function to process extracted text
sub process_text {
    my ($text) = @_;
    my ($date, $author, $table_info) = ('', '', '');

    # Assuming date and author are in the first few lines
    foreach my $line (@$text) {
        if ($line =~ /Date:\s*(\d{1,2}\/\d{1,2}\/\d{4})/) {
            $date = $1;
        } elsif ($line =~ /Author:\s*(\w+)/) {
            $author = $1;
        } else {
            last if $line =~ /^\s*$/;  # Break if an empty line is encountered
            $table_info .= $line . "\n";
        }
    }

    return ($date, $author, $table_info);
}

# Main
